"use strict";(self.webpackChunkhydra_head_protocol_docs=self.webpackChunkhydra_head_protocol_docs||[]).push([[508],{92635:e=>{e.exports=JSON.parse('{"pluginId":"core-concepts","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"defaultSidebar":[{"type":"link","label":"Learn","href":"/head-protocol/unstable/core-concepts/","docId":"index"},{"type":"link","label":"Scalability","href":"/head-protocol/unstable/core-concepts/scalability","docId":"scalability"},{"type":"link","label":"Layer 2 solutions","href":"/head-protocol/unstable/core-concepts/layer-two","docId":"layer-two"},{"type":"link","label":"Hydra Head protocol overview","href":"/head-protocol/unstable/core-concepts/protocol-overview","docId":"protocol-overview"},{"type":"link","label":"API Behavior","href":"/head-protocol/unstable/core-concepts/behavior","docId":"behavior"},{"type":"link","label":"Specification","href":"/head-protocol/unstable/core-concepts/specification","docId":"specification"}]},"docs":{"behavior":{"id":"behavior","title":"API Behavior","description":"This page will soon move into the API reference itself.","sidebar":"defaultSidebar"},"index":{"id":"index","title":"Learn","description":"","sidebar":"defaultSidebar"},"layer-two":{"id":"layer-two","title":"Layer 2 solutions","description":"This section provides an overview of various types of layer 2 solutions, along with several examples.","sidebar":"defaultSidebar"},"protocol-overview":{"id":"protocol-overview","title":"Hydra Head protocol overview","description":"Hydra is the layer 2 scalability solution for Cardano, designed to increase transaction speed through low latency and high throughput while minimizing transaction costs. Hydra Head is the first protocol of the Hydra family that lays the foundation for more advanced deployment scenarios using isomorphic, multi-party state channels. For an introduction to the protocol, refer to these two blog posts:","sidebar":"defaultSidebar"},"scalability":{"id":"scalability","title":"Scalability","description":"Decentralized systems, including blockchains, face fundamental scalability limitations due to their reliance on global transaction replication to ensure security. This constraint is commonly known as the blockchain trilemma, where decentralization, security, and scalability counteract each other. Although Cardano employs an efficient consensus algorithm, its global distribution among thousands of block-producing nodes results in block creation approximately every twenty seconds. During peak transaction times, this can lead to increased settlement times as transactions may not be included in the immediate next block.","sidebar":"defaultSidebar"},"specification":{"id":"specification","title":"Specification","description":"The specification is currently written in LaTeX and can be edited in the Hydra repository. You can view the rendered version below or download it for fullscreen viewing here.","sidebar":"defaultSidebar"}}}')}}]);